import { _decorator, Component, Graphics, Animation, UITransform, Color } from 'cc';
import { ReelController2 } from './ReelController2';

const { ccclass } = _decorator;

@ccclass('WinEffectController')
export class WinEffectController extends Component {

    private reelController: ReelController2 | null = null;

    onLoad() {
        this.reelController = this.getComponent(ReelController2);
        if (!this.reelController) {
            console.warn("[WinEffectController] ReelController not found on same node.");
        }
    }

    public async drawWinningReelsBordersAndAnimate(winIndexes: number[], color: Color, lineNumber: number) {
        if (!this.reelController) return;

        for (const idx of winIndexes) {
            const col = Math.floor(idx / 3);
            const row = idx % 3;

            const reelNode = this.reelController.cells[col]?.[row];
            if (!reelNode) continue;

            const graphicsNode = reelNode.getChildByName("Graphics");
            if (!graphicsNode) continue;

            const ctx = graphicsNode.getComponent(Graphics);
            const anim = reelNode.getComponent(Animation);
            const uiTransform = reelNode.getComponent(UITransform);
            if (!ctx || !uiTransform) continue;

            const size = uiTransform.contentSize;
            const left = -size.width / 2;
            const bottom = -size.height / 2;

            ctx.strokeColor = color;
            ctx.rect(
                left + lineNumber,
                bottom + lineNumber,
                size.width - lineNumber * 2,
                size.height - lineNumber * 2
            );
            ctx.stroke();

            if (anim) {
                anim.play();
                await new Promise<void>((resolve) => {
                    anim.once(Animation.EventType.FINISHED, () => resolve());
                });
            }
        }
    }

    public clearReelsBorders() {
        if (!this.reelController) return;

        for (const colCells of this.reelController.cells) {
            for (const cell of colCells) {
                const graphicsNode = cell.getChildByName("Graphics");
                if (!graphicsNode) continue;
                graphicsNode.getComponent(Graphics)?.clear();
            }
        }
    }
}
